sources.LerayHopf.cutoff:
/-- The smooth radial cutoff at scale `R`: `cutoff R x = χ ((1/R) • x)`. -/
private noncomputable def cutoff (R : ℝ) : Domain3 → ℝ :=
  fun x => (cutoffBump : Domain3 → ℝ) ((1 / R) • x)

sources.LerayHopf.cxify:
/-- Complexification of a real Schwartz map: post-compose with `ofRealCLM : ℝ →L[ℝ] ℂ`. -/
private noncomputable def cxify (φ : SchwartzMap Domain3 ℝ) : SchwartzMap Domain3 ℂ :=
  φ.postcompCLM (RCLike.ofRealCLM (K := ℂ))

sources.LerayHopf.cxifyH1:
/-- Local complexification of a real Schwartz map (the CurlDensity `schwartzC` is private). -/
private noncomputable def cxifyH1 (f : SchwartzMap Domain3 ℝ) : SchwartzMap Domain3 ℂ :=
  f.postcompCLM (RCLike.ofRealCLM (K := ℂ))

sources.LerayHopf.fourier_sub_L2C:
/-- `𝓕` on `L2C_R3` distributes over subtraction. -/
private theorem fourier_sub_L2C (A B : L2C_R3) : 𝓕 (A - B) = 𝓕 A - 𝓕 B :=
  map_sub (AddMonoidHom.mk' (𝓕 : L2C_R3 → L2C_R3) fourier_add) A B

sources.LerayHopf.hasSchwartzComponents_of_basis:
private theorem hasSchwartzComponents_of_basis (B : SchwartzGalerkinBasis) (k : ℕ) :
    HasSchwartzComponents (B.e k) :=
  B.e_schwartz k

sources.LerayHopf.isSchwartzComp_curlSchwartzL2:
private theorem isSchwartzComp_curlSchwartzL2 (ψ : Fin 3 → SchwartzMap Domain3 ℝ) :
    IsSchwartzComp (curlSchwartzL2 ψ) :=
  ⟨curlSchwartz ψ, fun j => curlSchwartzL2_projComponent ψ j⟩

sources.LerayHopf.mFourierCoeff3_add:
private lemma mFourierCoeff3_add (f g : L2C) (k : Fin 3 → ℤ) :
    mFourierCoeff3 (f + g) k = mFourierCoeff3 f k + mFourierCoeff3 g k := by
  simp only [mFourierCoeff3, map_add, lp.coeFn_add, Pi.add_apply]

sources.LerayHopf.memH1VF_of_galerkinTest:
/-- A Galerkin test is H¹: finite Fourier support ⟹ every Sobolev norm finite. -/
private theorem memH1VF_of_galerkinTest {w : L2Sigma} (hw : IsGalerkinTest w) :
    memH1VF (w : L2VF) := (galerkinTestSpan_subset_H1Sigma hw).2

sources.LerayHopf.negLapSchwartz:
/-- The scalar **negative Laplacian** of a real Schwartz map, `-Δ f = -∑ₐ ∂ₐ∂ₐ f`, as a Schwartz
map (so it carries a canonical `L²`-class `(negLapSchwartz f).toLp`). -/
private noncomputable def negLapSchwartz (f : SchwartzMap Domain3 ℝ) : SchwartzMap Domain3 ℝ :=
  - ∑ a : Fin 3, ∂_{(EuclideanSpace.single a (1 : ℝ) : Domain3)}
      (∂_{(EuclideanSpace.single a (1 : ℝ) : Domain3)} f)

sources.LerayHopf.prodS:
/-- The pointwise product of two real Schwartz functions, as a Schwartz function. -/
private noncomputable def prodS (f g : SchwartzMap Domain3 ℝ) : SchwartzMap Domain3 ℝ :=
  SchwartzMap.bilinLeftCLM (ContinuousLinearMap.mul ℝ ℝ) g.hasTemperateGrowth f

sources.LerayHopf.prodS_apply:
private theorem prodS_apply (f g : SchwartzMap Domain3 ℝ) (x : Domain3) :
    (prodS f g) x = f x * g x := by
  simp [prodS, SchwartzMap.bilinLeftCLM_apply]

sources.LerayHopf.reLp:
/-- The real-part map `L²(ℝ³;ℂ) → L²(ℝ³;ℝ)` as a continuous linear map (via `Complex.reCLM`). -/
private noncomputable def reLp : L2C_R3 →L[ℝ] Lp ℝ 2 (volume : Measure Domain3) :=
  Complex.reCLM.compLpL 2 (volume : Measure Domain3)

sources.LerayHopf.scaleCLM:
/-- The scaling operator `(1/R) • id` on `Domain3`, used to express `cutoff R = χ ∘ ((1/R)•·)`. -/
private noncomputable def scaleCLM (R : ℝ) : Domain3 →L[ℝ] Domain3 :=
  (1 / R) • ContinuousLinearMap.id ℝ Domain3

sources.LerayHopf.schwartzC:
/-- Complexification of a real Schwartz map by post-composing with `ℝ →L[ℝ] ℂ`. -/
private noncomputable def schwartzC (f : SchwartzMap Domain3 ℝ) : SchwartzMap Domain3 ℂ :=
  f.postcompCLM (RCLike.ofRealCLM (K := ℂ))

sources.LerayHopf.symbolMul:
/-- The complex Schwartz-symbol multiplier `ξ ↦ -(2π i)⁻¹ (a² + ‖ξ‖²)⁻¹`. -/
private noncomputable def symbolMul (a : ℝ) : Domain3 → ℂ :=
  fun ξ => (-(2 * Real.pi * Complex.I)⁻¹) * ((yukawaMul a ξ : ℝ) : ℂ)

sources.LerayHopf.viscousFormSq_eq_sum_integrand:
private theorem viscousFormSq_eq_sum_integrand (w : L2VF_R3) :
    viscousFormSq_R3 1 w = ∑ j : Fin 3, viscousIntegrand_j j w :=
  FourierL2.viscousFormSq_R3_eq_integral_normSq_fourier w

sources.LerayHopf.viscousIntegrand_j_nonneg:
private theorem viscousIntegrand_j_nonneg (j : Fin 3) (w : L2VF_R3) :
    0 ≤ viscousIntegrand_j j w :=
  integral_nonneg (fun ξ => by positivity)
